// Recoloca a referência do binário do Webhook no item atual.
// O nó HTTP "Validate Admin RPC" substitui o item e descarta o binário;
// aqui restauramos a metadata (com o id do arquivo em filesystem) para que o
// próximo Code Node possa lê-lo via this.helpers.getBinaryDataBuffer.
const wh = $('Webhook Trigger1').first();
if (!wh || !wh.binary || !Object.keys(wh.binary).length) {
  throw new Error('O webhook não recebeu nenhum arquivo binário.');
}
const item = $input.first();
item.binary = wh.binary;
return [item];

// ===== Parse CSV & Detect (estilo exemplo.json) =====
// Faz parse do CSV enviado e detecta UM de dois formatos possíveis:
//   catalogo_produtos -> imagens_bahia_produtos_rows  (referencia/SKU, Codigo_de_preco, Nome, NCM...)
//   catalogo_precos    -> imagens_bahia_precos        (codigo, valor_padrao_varejo, valor_*...)
// O binário é restaurado no nó anterior ("Restaurar Binário") e lido aqui com
// this.helpers.getBinaryDataBuffer — único helper suportado no Code Node (Cloud,
// binaryDataMode=filesystem). Não usa SpreadsheetFile nem getBinaryStream.

const bin = $input.first().binary || {};
const binProp = bin.file ? 'file' : Object.keys(bin)[0];
if (!binProp) {
  throw new Error('O webhook não recebeu nenhum arquivo binário.');
}
const buf = await this.helpers.getBinaryDataBuffer(0, binProp);

let text = buf.toString('utf8');
if (((text.match(/\uFFFD/g) || []).length) > 3) text = buf.toString('latin1');
text = text.replace(/^\uFEFF/, '');

const lines = text.split(/\r?\n/).filter((l) => l.trim().length);
if (!lines.length) throw new Error('Arquivo vazio.');

// Detecta o separador (',' ou ';').
const sniff = lines.slice(0, 8).join('\n');
const delim = ((sniff.split(';').length) >= (sniff.split(',').length)) ? ';' : ',';

function parseLine(line) {
  const out = []; let cur = ''; let q = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (q) {
      if (ch === '"') { if (line[i + 1] === '"') { cur += '"'; i++; } else q = false; }
      else cur += ch;
    } else {
      if (ch === '"') q = true;
      else if (ch === delim) { out.push(cur); cur = ''; }
      else cur += ch;
    }
  }
  out.push(cur);
  return out.map((s) => s.trim());
}

const header = parseLine(lines[0]);
const rows = [];
for (let i = 1; i < lines.length; i++) {
  const cells = parseLine(lines[i]);
  if (cells.every((c) => c === '')) continue;
  const o = {};
  header.forEach((k, idx) => { if (k) o[k] = cells[idx] != null ? cells[idx] : ''; });
  rows.push(o);
}
if (!rows.length) throw new Error('Nenhuma linha de dados encontrada no arquivo.');

// Detecta o formato a partir do cabeçalho.
const hj = header.join('|').toLowerCase();
let tipo = null;
if (hj.includes('valor_') || hj.includes('tabela_numero')) {
  tipo = 'catalogo_precos';
} else if (hj.includes('codigo_de_preco') || hj.includes('referencia/sku') || hj.includes('ncm') || hj.includes('nome')) {
  tipo = 'catalogo_produtos';
}
if (!tipo) {
  throw new Error('Formato não reconhecido: envie o CSV de produtos (imagens_bahia_produtos_rows) ou de preços (imagens_bahia_precos).');
}

return rows.map((r) => ({ json: Object.assign({}, r, { _tipo: tipo }) }));

// Após o TRUNCATE (cujo output é vazio), recupera as linhas já parseadas
// do nó "Parse CSV & Detect" para alimentar o INSERT (snapshot completo).
return $('Parse CSV & Detect').all().map((it) => {
  const j = Object.assign({}, it.json);
  delete j._tipo;
  return { json: j };
});

// ===== Code Node: Limpeza de Preços (tabela WIDE) =====
// Converte vírgula decimal BR -> ponto (float US) em TODAS as colunas valor_*.

function brParaFloat(v) {
  if (v === undefined || v === null) return null;
  let s = String(v).trim();
  if (s === '') return null;
  if (s.indexOf(',') !== -1) s = s.replace(/\./g, '');
  s = s.replace(',', '.');
  s = s.replace(/[^0-9.\-]/g, '');
  const n = parseFloat(s);
  return Number.isNaN(n) ? null : n;
}

const saida = items.map((item) => {
  const out = {};
  for (const [k, v] of Object.entries(item.json)) {
    const key = String(k).trim();
    if (key.startsWith('valor_')) {
      out[key] = brParaFloat(v);
    } else if (key === 'tabela_numero') {
      const n = parseInt(String(v).replace(/\D/g, ''), 10);
      if (!Number.isNaN(n)) out[key] = n;
    } else if (key === 'codigo' || key === 'resina_ref') {
      const s = v === undefined || v === null ? '' : String(v).trim();
      out[key] = s === '' ? null : s;
    }
  }
  return { json: out };
});

return saida.filter((i) => i.json.codigo);
